CREATE VIEW "catalog"."product_price_range" AS (select "catalog"."item_pricing"."project_id", "catalog"."variant"."product_id", "catalog"."item_pricing"."currency", MIN("catalog"."item_pricing"."amount_minor") as "min_amount_minor", MAX("catalog"."item_pricing"."amount_minor") as "max_amount_minor" from "catalog"."item_pricing" inner join "catalog"."variant" on "catalog"."variant"."id" = "catalog"."item_pricing"."variant_id" AND "catalog"."variant"."deleted_at" IS NULL where "catalog"."item_pricing"."effective_to" IS NULL group by "catalog"."item_pricing"."project_id", "catalog"."variant"."product_id", "catalog"."item_pricing"."currency");